export async function rotateApiKey(
  apiKeyId: string,
): Promise<ActionResponse<GeneratedApiKey & { name: string }>> {
  const supabase = await createClient();

  // Check authentication
  const {
    data: { user },
    error: authError,
  } = await supabase.auth.getUser();
  if (authError || !user) {
    return { success: false, error: "Unauthorized: User not authenticated." };
  }

  // Get active tenant ID
  const tenantId = await getActiveTenantId();
  if (!tenantId) {
    return { success: false, error: "No active tenant selected." };
  }

  try {
    // Get the existing key
    const { data: existingKey, error: fetchError } = await supabase
      .from("api_keys")
      .select("*")
      .eq("id", apiKeyId)
      .eq("tenant_id", tenantId)
      .single();

    if (fetchError || !existingKey) {
      return { success: false, error: "API key not found or access denied." };
    }

    // Determine environment from key_prefix
    const environment = existingKey.key_prefix.includes("_live_")
      ? "live"
      : "test";

    // Calculate new expiry (same duration as original if it had one)
    let expiresAt: string | null = null;
    if (existingKey.expires_at) {
      const originalExpiry = new Date(existingKey.expires_at);
      const originalCreated = new Date(existingKey.created_at || Date.now());
      const durationMs = originalExpiry.getTime() - originalCreated.getTime();
      expiresAt = new Date(Date.now() + durationMs).toISOString();
    }

    // Generate new key with same settings
    const { data: generatedKey, error: generateError } = await supabase.rpc(
      "generate_api_key" as any,
      {
        p_environment: environment,
        p_name: existingKey.name + " (Rotated)",
        p_tenant_id: tenantId,
        p_website_id: existingKey.website_id,
        p_created_by: user.id,
        p_scopes: existingKey.scopes,
        p_rate_limit: existingKey.rate_limit || 1000,
        p_expires_at: expiresAt,
        p_metadata: existingKey.metadata,
      },
    );

    if (generateError || !generatedKey || typeof generatedKey !== "object") {
      console.error("Error generating new API key:", generateError);
      return { success: false, error: "Failed to generate new API key." };
    }

    const keyData = generatedKey as GeneratedApiKey;

    // CRITICAL: Validate the generated key before returning it
    if (keyData.key && !validateGeneratedKey(keyData.key, environment)) {
      console.error("Rotated API key failed validation checks");

      // Revoke the new key immediately since it's invalid
      await supabase
        .from("api_keys")
        .update({
          is_active: false,
          revoked_at: new Date().toISOString(),
          revoked_by: user.id,
        })
        .eq("id", keyData.key_id);

      return {
        success: false,
        error:
          "Generated API key failed security validation. Please try again.",
      };
    }

    // Revoke the old key
    await supabase
      .from("api_keys")
      .update({
        is_active: false,
        revoked_at: new Date().toISOString(),
        revoked_by: user.id,
        metadata: {
          ...(existingKey.metadata as any),
          rotated_to: keyData.key_id,
        },
      })
      .eq("id", apiKeyId);

    revalidatePath("/dashboard/api-keys");
    return {
      success: true,
      data: {
        ...keyData,
        name: existingKey.name + " (Rotated)",
      },
    };
  } catch (error) {
    console.error("Unexpected error rotating API key:", error);
    return { success: false, error: "An unexpected error occurred." };
  }
}
